body:
Hi,
I'm getting this error when compiling with icarus version 11.0

iverilog -g2012 test.sv

test.sv:51: internal error: I do not know how to elaborate (ivl_type_t) this expression. 
test.sv:51:               : Expression is: (bit8_lsb1)<<(axsize)
test.sv:51:               : Expression type: 8PEBShift
test.sv:61: internal error: I do not know how to elaborate (ivl_type_t) this expression. 
test.sv:61:               : Expression is: (ByteCount)-(unaligned_byte_shift)
test.sv:61:               : Expression type: 8PEBinary

What's the workaround ?
I want to shift the value of 1 up to 8 bits to the left (acting like a multiply).

Thanks,
David


test.sv

//`define C_AXI_DATA_WIDTH 32

module xyz #( parameter integer C_AXI_DATA_WIDTH = 32);

 typedef struct packed {
   bit [7-1:0]     addr;
   bit             excl;
   bit [8-1:0]     len ;
   bit [3-1:0]     size;
   bit [2-1:0]     burst;
//   bit [C_AXI_ID_WIDTH-1:0]  id;
   bit [32-1:0]  id;
 } t_cmd_message;


  typedef bit [7:0] byte_da_t[];

  function automatic byte_da_t ByteCount (input t_cmd_message Burst, input [9:0] Beat); // david 09/17/2019 added bit type to check compilation
//  function [7:0] ByteCount; // david 09/17/2019 added bit type to check compilation
    byte_da_t ByteCount; // david
//    input t_cmd_message Burst;         // burst vector
//    input [9:0]        Beat;           // beat number in the burst (1-256)
    reg   [6:0]        axaddr;
    reg   [2:0]        axsize;
    reg   [7:0]        axlen;
    reg   [1:0]        axburst;
    reg [7:0] bit8_lsb1 = 8'b00000001; // david hack
    integer bus_data_bytes;
    integer unaligned_byte_shift;
  begin
    axaddr  = Burst.addr;
    axsize  = Burst.size;
    axlen   = Burst.len;
    axburst = Burst.burst;

//    localparam integer C_AXI_DATA_WIDTH=32;
//    localparam C_AXI_DATA_WIDTH = 32;

    bus_data_bytes = C_AXI_DATA_WIDTH/8;

    // Number of bytes that the data needs to be shifted when
    // the address is unaligned
    unaligned_byte_shift =
      axaddr &              // Byte address
      ((bit8_lsb1 << axsize) - 1);      //   masked by the number of bytes
//      ((1 << axsize) - 1);      //   masked by the number of bytes
//      ((8'b00000001 << axsize) - 1);      //   masked by the number of bytes
                            //   in a transfer

    // The number of valid bits depends on the transfer size.
    ByteCount = (bit8_lsb1 << axsize);
//    ByteCount = (8'b00000001 << axsize);
//    ByteCount = (1<<axsize);
    // For FIXED bursts or on the first beat of an INCR burst
    // if the address is unaligned modify the number of
    // valid strobe bits
    if ((axburst == 0) || (Beat == 0))
    begin
      // The number of valid bits depends on the transfer size
      // and the offset of the unaligned address.
      ByteCount = ByteCount - unaligned_byte_shift;
    end
  end
  endfunction // ByteCount

endmodule
